parameters.jsCode:
// Pega todos os itens da entrada do nó no n8n
const items = $input.all();

// Regex para identificar mensagens fora de escopo (sociais, importação, contatos específicos, vagas, links)
const regexFiltro = /(^\s*(bom dia|boa tarde|boa noite|obrigado|obrigada|muito obrigado)[.,!?\s]*$)|(\b(exterior|importa[çc][ãa]o|importar)\b)|(\bcontato\s+(comercial|de\s+vendedor)\b|\bvendedor\s+(da|do)\b)|(\b(vaga[s]?|oportunidade\s+aberta|clt|sal[áa]rio)\b)|(https?:\/\/|www\.)/i;

// Mapeia e atualiza cada item do input
return items.map(item => {
    // Garante que estamos lendo a mensagem corretamente, evitando erros se o campo não existir
    const mensagem = item.json.message || "";

    // Testa se a mensagem aciona alguma das regras do Regex
    if (regexFiltro.test(mensagem)) {
        // Classifica como ignorar direto no n8n, poupando o agente
        item.json.intencao = "ignorar";
        item.json.motivo_regex = "Bloqueado na triagem rápida (Social, Importação, Vaga, Link ou Contato específico)";
    } else {
        // Classifica como 'analisar' para que um nó de Switch (ou IF) envie para o LLM
        item.json.intencao = "analisar";
    }

    return item;
});

